import { ChartContainer } from "@repo/components";

const data = [
  { month: "Jan", value: 42 },
  { month: "Feb", value: 58 },
  { month: "Mar", value: 34 },
  { month: "Apr", value: 72 },
  { month: "May", value: 64 },
  { month: "Jun", value: 88 },
];

export default function ChartLine() {
  const max = Math.max(...data.map((d) => d.value));
  const points = data
    .map((d, i) => {
      const x = (i / (data.length - 1)) * 100;
      const y = 100 - (d.value / max) * 80;
      return `${x},${y}`;
    })
    .join(" ");

  return (
    <ChartContainer className="w-full max-w-md rounded-lg border p-4">
      <div className="mb-4 text-sm font-medium">Revenue over time</div>
      <div className="relative h-44">
        <svg viewBox="0 0 100 100" className="h-full w-full" preserveAspectRatio="none">
          <polyline points={points} fill="none" stroke="#8b5cf6" strokeWidth="1" vectorEffect="non-scaling-stroke" />
        </svg>
      </div>
    </ChartContainer>
  );
}

import { ChartContainer } from "@repo/components";

const data = [
  { label: "Desktop", value: 55, color: "#3b82f6" },
  { label: "Mobile", value: 35, color: "#10b981" },
  { label: "Tablet", value: 10, color: "#f59e0b" },
];

export default function ChartPie() {
  const total = data.reduce((sum, d) => sum + d.value, 0);
  let cumulative = 0;

  const segments = data.map((d) => {
    const start = (cumulative / total) * 100;
    cumulative += d.value;
    const end = (cumulative / total) * 100;
    return { ...d, start, end };
  });

  return (
    <ChartContainer className="w-full max-w-md rounded-lg border p-4">
      <div className="mb-4 text-sm font-medium">Device usage</div>
      <div className="flex items-center gap-6">
        <div className="relative h-40 w-40 shrink-0">
          <svg viewBox="0 0 36 36" className="h-full w-full -rotate-90">
            {segments.map((seg, i) => (
              <circle key={i} cx="18" cy="18" r="14" fill="none" stroke={seg.color} strokeWidth="5"
                strokeDasharray={`${seg.end - seg.start} ${100 - (seg.end - seg.start)}`} strokeDashoffset={-seg.start} />
            ))}
          </svg>
        </div>
        <div className="space-y-3">
          {data.map((d) => (
            <div key={d.label} className="flex items-center gap-2">
              <div className="h-3 w-3 rounded-full" style={{ backgroundColor: d.color }} />
              <span className="text-sm text-muted-foreground">{d.label}</span>
              <span className="text-sm font-medium ml-auto">{d.value}%</span>
            </div>
          ))}
        </div>
      </div>
    </ChartContainer>
  );
}

import { ChartContainer } from "@repo/components";

const data = [
  { month: "Jan", direct: 30, organic: 40, referral: 20 },
  { month: "Feb", direct: 45, organic: 35, referral: 25 },
  { month: "Mar", direct: 35, organic: 50, referral: 30 },
  { month: "Apr", direct: 50, organic: 45, referral: 20 },
];

export default function ChartStacked() {
  const max = Math.max(...data.map((d) => d.direct + d.organic + d.referral));

  return (
    <ChartContainer className="w-full max-w-md rounded-lg border p-4">
      <div className="mb-4 text-sm font-medium">Traffic sources</div>
      <div className="flex h-44 items-end gap-3">
        {data.map((item) => {
          const total = item.direct + item.organic + item.referral;
          const h = (total / max) * 128;
          return (
            <div key={item.month} className="flex flex-1 flex-col items-center gap-2">
              <div className="flex w-full flex-col" style={{ height: h }}>
                <div className="w-full rounded-t" style={{ flex: item.referral, backgroundColor: "#f59e0b" }} />
                <div className="w-full" style={{ flex: item.organic, backgroundColor: "#10b981" }} />
                <div className="w-full rounded-b" style={{ flex: item.direct, backgroundColor: "#3b82f6" }} />
              </div>
              <span className="text-xs text-muted-foreground">{item.month}</span>
            </div>
          );
        })}
      </div>
    </ChartContainer>
  );
}

